CREATE TABLE IF NOT EXISTS public.system_settings ( key TEXT PRIMARY KEY, value JSONB NOT NULL, description TEXT, updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(), updated_by UUID REFERENCES public.user_profiles(id) ); ALTER TABLE public.system_settings ENABLE ROW LEVEL SECURITY; CREATE POLICY "Admins can view system settings" ON public.system_settings FOR SELECT USING (public.is_admin()); CREATE POLICY "Admins can update system settings" ON public.system_settings FOR UPDATE USING (public.is_admin());
